#!/usr/bin/env bash
# Generated by bun-bench Harbor export adapter. Oracle reference solution.
# Overwrites the starter source under /app with the bun-bench reference.
set -euo pipefail

mkdir -p /app/src
cat > /app/src/server.ts <<'BUN_BENCH_SOLUTION_EOF'
const port = Number(Bun.env.PORT ?? 3000);
const counts = new Map<string, number>();

Bun.serve({
  port,
  fetch(request) {
    const url = new URL(request.url);

    if (request.method === "GET" && url.pathname === "/limited") {
      const clientId = request.headers.get("x-client-id");
      if (!clientId) {
        return Response.json({ error: "bad_request" }, { status: 400 });
      }

      const count = counts.get(clientId) ?? 0;
      if (count >= 2) {
        return Response.json({ error: "rate_limited" }, { status: 429 });
      }

      counts.set(clientId, count + 1);
      return Response.json({ ok: true, remaining: 1 - count }, { status: 200 });
    }

    return Response.json({ error: "not_found" }, { status: 404 });
  },
});

console.log(`reference server listening on ${port}`);
BUN_BENCH_SOLUTION_EOF
